import { ChatMessage } from '../types/chat';

export const messages: ChatMessage[] = [
  { id: 'm1', role: 'assistant', content: 'Hello! **How** can I *help* you today?' },
  { id: 'm2', role: 'user', content: 'I would like to know more about the new feature.' },
  { id: 'm3', role: 'assistant', content: 'Sure! Here is a list:\n- Feature A\n- Feature B\n- Feature C' },
  { id: 'm4', role: 'user', content: 'Great, thanks! Can you show me some code?' },
  { id: 'm5', role: 'assistant', content: '```js\nconsole.log("Hello World");\n```' },
  { id: 'm6', role: 'user', content: 'Looks good 👍' },
];
